parameters.functionCode:
const webhookSecret = $input.first().json.headers?.['x-webhook-secret'];

if (webhookSecret !== $env.N8N_WEBHOOK_SECRET) {
  throw new Error('Invalid webhook secret');
}

return [{ json: $input.first().json.body }];

parameters.jsonBody:
={
  "messages": [
    {
      "role": "system",
      "content": "You are a German language tutor. This text was extracted from a student's handwritten homework using OCR. Clean up OCR artifacts, correct German grammar, and explain corrections in simple English. Note potential OCR misreads (e.g., similar-looking characters). Respond as valid JSON: {\"corrected\": \"...\", \"explanation\": \"...\"}"
    },
    {
      "role": "user",
      "content": "Please correct this OCR-extracted German text: {{ $json.ocr_text }}"
    }
  ],
  "temperature": 0.3,
  "max_tokens": 1000
}

parameters.functionCode:
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';
const ocrText = $('Validate Request').first().json.ocr_text || '';

let parsed;
try {
  parsed = JSON.parse(content);
} catch {
  parsed = {
    corrected: content,
    explanation: 'The AI returned a non-structured response.'
  };
}

return [{
  json: {
    original: ocrText,
    transcription: ocrText,
    corrected: parsed.corrected || '',
    explanation: parsed.explanation || ''
  }
}];
